export interface PortData {
	id: number; // 数据id
	latitude: number; // 纬度
	longitude: number; // 经度
	lat: number; // 纬度 (Google Maps 格式)
	lng: number; // 经度 (Google Maps 格式)
	vessel: string; // 航次数据/船名
	naviStatus: number; // 航行状�? 0=在航, 1=靠港 靠港表示这是一个港口
	hdg: string; // 航向 (Heading)
	cog: string; // 对地航向 (Course Over Ground)
	sog: string; // 对地航�?(Speed Over Ground)
	utc: string; // UTC时间
	[key: string]: any;
}

